package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringReader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreEmptyLines() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withIgnoreEmptyLines();

        // Then
        assertTrue(result.getIgnoreEmptyLines());
    }

    @Test
    public void testWithIgnoreEmptyLinesFalse() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);

        // When
        CSVFormat result = csvFormat.withIgnoreEmptyLines();

        // Then
        assertFalse(result.getIgnoreEmptyLines());
    }

    @Test
    public void testWithIgnoreEmptyLinesTwice() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withIgnoreEmptyLines().withIgnoreEmptyLines();

        // Then
        assertTrue(result.getIgnoreEmptyLines());
    }

    @Test
    public void testWithIgnoreEmptyLinesExcel() {
        // Given
        CSVFormat csvFormat = CSVFormat.EXCEL;

        // When
        CSVFormat result = csvFormat.withIgnoreEmptyLines();

        // Then
        assertFalse(result.getIgnoreEmptyLines());
    }

    @Test
    public void testWithAllowMissingColumnNames() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withAllowMissingColumnNames();

        // Then
        assertTrue(result.getAllowMissingColumnNames());
    }

    @Test
    public void testWithAllowMissingColumnNamesFalse() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);

        // When
        CSVFormat result = csvFormat.withAllowMissingColumnNames();

        // Then
        assertFalse(result.getAllowMissingColumnNames());
    }

    @Test
    public void testWithAllowMissingColumnNamesTwice() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withAllowMissingColumnNames().withAllowMissingColumnNames();

        // Then
        assertTrue(result.getAllowMissingColumnNames());
    }

}
